<template>
  <div class="product-list-container">
    <el-card class="box-card">
      <!-- 搜索和操作区域 -->
      <div class="filter-container">
        <el-form :inline="true" :model="listQuery" class="demo-form-inline">
          <el-form-item label="商品名称">
            <el-input v-model="listQuery.keyword" placeholder="商品名称" clearable></el-input>
          </el-form-item>
          <el-form-item label="分类">
            <el-select v-model="listQuery.categoryId" placeholder="选择分类" clearable>
              <el-option v-for="item in categoryOptions" :key="item.value" :label="item.label" :value="item.value"></el-option>
            </el-select>
          </el-form-item>
          <el-form-item label="状态">
            <el-select v-model="listQuery.status" placeholder="商品状态" clearable>
              <el-option label="上架" :value="1"></el-option>
              <el-option label="下架" :value="0"></el-option>
            </el-select>
          </el-form-item>
          <el-form-item>
            <el-button type="primary" @click="handleSearch">查询</el-button>
            <el-button @click="resetQuery">重置</el-button>
          </el-form-item>
        </el-form>
      </div>
      
      <!-- 操作按钮区域 -->
      <div class="action-container">
        <el-button type="primary" @click="handleAdd">添加商品</el-button>
        <el-button type="warning" @click="handleBatchUpdateStatus(1)" :disabled="!selectedItems.length">批量上架</el-button>
        <el-button type="info" @click="handleBatchUpdateStatus(0)" :disabled="!selectedItems.length">批量下架</el-button>
        <el-button type="danger" @click="handleBatchDelete" :disabled="!selectedItems.length">批量删除</el-button>
      </div>
      
      <!-- 表格区域 -->
      <el-table
        v-loading="listLoading"
        :data="list"
        element-loading-text="加载中..."
        border
        fit
        highlight-current-row
        @selection-change="handleSelectionChange"
      >
        <el-table-column type="selection" width="55"></el-table-column>
        <el-table-column prop="id" label="ID" width="80"></el-table-column>
        <el-table-column label="商品图片" width="120">
          <template slot-scope="scope">
            <img :src="scope.row.imageUrl" alt="" class="product-img">
          </template>
        </el-table-column>
        <el-table-column prop="name" label="商品名称" min-width="150"></el-table-column>
        <el-table-column prop="categoryName" label="分类" width="120"></el-table-column>
        <el-table-column prop="price" label="价格" width="100">
          <template slot-scope="scope">
            ¥{{ scope.row.price.toFixed(2) }}
          </template>
        </el-table-column>
        <el-table-column prop="originalPrice" label="原价" width="100">
          <template slot-scope="scope">
            <span class="original-price">¥{{ scope.row.originalPrice.toFixed(2) }}</span>
          </template>
        </el-table-column>
        <el-table-column prop="stock" label="库存" width="100">
          <template slot-scope="scope">
            <span :class="{'low-stock': scope.row.stock < 20}">
              {{ scope.row.stock }}
              <el-tag v-if="scope.row.stock < 20" type="danger" size="mini">预警</el-tag>
            </span>
          </template>
        </el-table-column>
        <el-table-column prop="tags" label="标签" width="150">
          <template slot-scope="scope">
            <el-tag v-if="scope.row.isNew" type="success" size="mini" style="margin-right: 5px;">新品</el-tag>
            <el-tag v-if="scope.row.isHot" type="danger" size="mini" style="margin-right: 5px;">热销</el-tag>
            <el-tag v-if="scope.row.isRecommend" type="warning" size="mini">推荐</el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="salesCount" label="销量" width="100"></el-table-column>
        <el-table-column prop="status" label="状态" width="100">
          <template slot-scope="scope">
            <el-tag :type="scope.row.status ? 'success' : 'info'">
              {{ scope.row.status ? '已上架' : '已下架' }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column label="操作" width="230" fixed="right">
          <template slot-scope="scope">
            <el-button size="mini" @click="handleView(scope.row)">查看</el-button>
            <el-button size="mini" type="primary" @click="handleEdit(scope.row)">编辑</el-button>
            <el-button 
              size="mini" 
              :type="scope.row.status ? 'info' : 'success'"
              @click="handleUpdateStatus(scope.row)"
            >
              {{ scope.row.status ? '下架' : '上架' }}
            </el-button>
            <el-button size="mini" type="danger" @click="handleDelete(scope.row)">删除</el-button>
          </template>
        </el-table-column>
      </el-table>
      <el-empty v-if="!listLoading && list.length === 0" description="暂无数据" />
      
      <!-- 分页区域 -->
      <div class="pagination-container">
        <el-pagination
          background
          @size-change="handleSizeChange"
          @current-change="handleCurrentChange"
          :current-page="listQuery.page"
          :page-sizes="[10, 20, 30, 50]"
          :page-size="listQuery.pageSize"
          layout="total, sizes, prev, pager, next, jumper"
          :total="total"
        >
        </el-pagination>
      </div>
    </el-card>
  </div>
</template>

<script>
import productApi from '@/api/product'
import categoryApi from '@/api/category'

export default {
  name: 'ProductList',
  data() {
    return {
      list: [], // 商品列表
      total: 0, // 总记录数
      listLoading: true, // 加载状态
      listQuery: { // 查询参数
        page: 1,
        pageSize: 10,
        keyword: '',
        categoryId: '',
        status: ''
      },
      selectedItems: [], // 选中的商品
      categoryOptions: [], // 分类选项
    }
  },
  created() {
    this.fetchData()
    this.fetchCategories()
  },
  methods: {
    // 获取商品列表
    fetchData() {
      this.listLoading = true
      
      productApi.getList(this.listQuery)
        .then(response => {
          if (response.code === 0) {
            this.list = response.data.list || []
            this.total = response.data.total || 0
          } else {
            this.$message.error(response.message || '获取商品列表失败')
          }
          this.listLoading = false
        })
        .catch(error => {
          console.error('获取商品列表出错:', error)
          this.$message.error('获取数据失败，请稍后重试')
          this.listLoading = false
          
          // 模拟数据（实际开发中应该删除）
          this.mockProductList()
        })
    },
    
    // 获取分类列表
    fetchCategories() {
      categoryApi.getAll()
        .then(response => {
          if (response.code === 0) {
            this.categoryOptions = (response.data || []).map(item => ({
              value: item.id,
              label: item.name
            }))
          }
        })
        .catch(error => {
          console.error('获取分类列表出错:', error)
          
          // 模拟数据（实际开发中应该删除）
          this.mockCategoryOptions()
        })
    },
    
    // 模拟商品数据（实际开发中应该删除）
    mockProductList() {
      this.list = [
        {
          id: 1,
          name: '西湖龙井 明前特级',
          imageUrl: 'https://img.alicdn.com/imgextra/i4/2201504853048/O1CN01fGEVqY1U6z4Kkrr30_!!2201504853048.jpg',
          categoryName: '绿茶',
          price: 268,
          originalPrice: 328,
          stock: 100,
          salesCount: 56,
          status: 1
        },
        {
          id: 2,
          name: '信阳毛尖 特级',
          imageUrl: 'https://img.alicdn.com/imgextra/i3/2201504853048/O1CN01RFneBp1U6z47E1uxE_!!2201504853048.jpg',
          categoryName: '绿茶',
          price: 198,
          originalPrice: 236,
          stock: 85,
          salesCount: 42,
          status: 1
        },
        {
          id: 3,
          name: '安溪铁观音 清香型',
          imageUrl: 'https://img.alicdn.com/imgextra/i1/2534960860/O1CN01hxCzpw2JOkQXGsN2l_!!2534960860.jpg',
          categoryName: '乌龙茶',
          price: 156,
          originalPrice: 196,
          stock: 120,
          salesCount: 31,
          status: 1
        },
        {
          id: 4,
          name: '武夷山大红袍',
          imageUrl: 'https://img.alicdn.com/imgextra/i1/2534960860/O1CN01sPpFkY2JOkODUaHF5_!!2534960860.jpg',
          categoryName: '乌龙茶',
          price: 298,
          originalPrice: 358,
          stock: 60,
          salesCount: 25,
          status: 0
        },
        {
          id: 5,
          name: '云南普洱 熟茶',
          imageUrl: 'https://img.alicdn.com/imgextra/i2/2201504853048/O1CN01Kx4M9K1U6z3lmLpol_!!2201504853048.jpg',
          categoryName: '黑茶',
          price: 228,
          originalPrice: 268,
          stock: 75,
          salesCount: 18,
          status: 1
        }
      ]
      
      this.total = this.list.length
    },
    
    // 模拟分类数据（实际开发中应该删除）
    mockCategoryOptions() {
      this.categoryOptions = [
        { value: 1, label: '绿茶' },
        { value: 2, label: '红茶' },
        { value: 3, label: '乌龙茶' },
        { value: 4, label: '白茶' },
        { value: 5, label: '黄茶' },
        { value: 6, label: '黑茶' }
      ]
    },
    
    // 搜索
    handleSearch() {
      this.listQuery.page = 1
      this.fetchData()
    },
    
    // 重置查询条件
    resetQuery() {
      this.listQuery = {
        page: 1,
        pageSize: 10,
        keyword: '',
        categoryId: '',
        status: ''
      }
      this.fetchData()
    },
    
    // 每页数量改变
    handleSizeChange(val) {
      this.listQuery.pageSize = val
      this.fetchData()
    },
    
    // 页码改变
    handleCurrentChange(val) {
      this.listQuery.page = val
      this.fetchData()
    },
    
    // 选择项改变
    handleSelectionChange(val) {
      this.selectedItems = val
    },
    
    // 查看商品
    handleView(row) {
      // 跳转到商品详情页
      window.open(`/product/detail/${row.id}`, '_blank')
    },
    
    // 添加商品
    handleAdd() {
      this.$router.push('/product/add')
    },
    
    // 编辑商品
    handleEdit(row) {
      this.$router.push(`/product/edit/${row.id}`)
    },
    
    // 删除商品
    handleDelete(row) {
      this.$confirm('确定要删除该商品吗？', '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(() => {
        productApi.delete(row.id)
          .then(response => {
            if (response.code === 0) {
              this.$message.success('删除成功')
              this.fetchData()
            } else {
              this.$message.error(response.message || '删除失败')
            }
          })
          .catch(error => {
            console.error('删除商品出错:', error)
            this.$message.error('删除失败，请重试')
          })
      }).catch(() => {
        // 取消删除
      })
    },
    
    // 批量删除
    handleBatchDelete() {
      if (this.selectedItems.length === 0) {
        this.$message.warning('请选择要删除的商品')
        return
      }
      
      const ids = this.selectedItems.map(item => item.id)
      
      this.$confirm(`确定要删除这${ids.length}件商品吗？`, '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(() => {
        productApi.batchDelete(ids)
          .then(response => {
            if (response.code === 0) {
              this.$message.success('批量删除成功')
              this.fetchData()
            } else {
              this.$message.error(response.message || '批量删除失败')
            }
          })
          .catch(error => {
            console.error('批量删除商品出错:', error)
            this.$message.error('批量删除失败，请重试')
          })
      }).catch(() => {
        // 取消删除
      })
    },
    
    // 更新商品状态（上架/下架）
    handleUpdateStatus(row) {
      const newStatus = row.status ? 0 : 1
      const statusText = newStatus ? '上架' : '下架'
      
      this.$confirm(`确定要${statusText}该商品吗？`, '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(() => {
        productApi.updateStatus(row.id, newStatus)
          .then(response => {
            if (response.code === 0) {
              this.$message.success(`${statusText}成功`)
              // 更新本地状态
              row.status = newStatus
            } else {
              this.$message.error(response.message || `${statusText}失败`)
            }
          })
          .catch(error => {
            console.error(`${statusText}商品出错:`, error)
            this.$message.error(`${statusText}失败，请重试`)
          })
      }).catch(() => {
        // 取消操作
      })
    },
    
    // 批量更新商品状态
    handleBatchUpdateStatus(status) {
      if (this.selectedItems.length === 0) {
        this.$message.warning('请选择要操作的商品')
        return
      }
      
      const ids = this.selectedItems.map(item => item.id)
      const statusText = status ? '上架' : '下架'
      
      this.$confirm(`确定要批量${statusText}这${ids.length}件商品吗？`, '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(() => {
        productApi.batchUpdateStatus(ids, status)
          .then(response => {
            if (response.code === 0) {
              this.$message.success(`批量${statusText}成功`)
              this.fetchData()
            } else {
              this.$message.error(response.message || `批量${statusText}失败`)
            }
          })
          .catch(error => {
            console.error(`批量${statusText}商品出错:`, error)
            this.$message.error(`批量${statusText}失败，请重试`)
          })
      }).catch(() => {
        // 取消操作
      })
    }
  }
}
</script>

<style lang="scss" scoped>
.product-list-container {
  padding: 20px;
  
  .filter-container {
    margin-bottom: 20px;
  }
  
  .action-container {
    margin-bottom: 20px;
    display: flex;
    
    .el-button {
      margin-right: 10px;
    }
  }
  
  .product-img {
    width: 80px;
    height: 80px;
    object-fit: cover;
    border-radius: 4px;
  }
  
  .original-price {
    color: #999;
    text-decoration: line-through;
  }
  
  .pagination-container {
    margin-top: 20px;
    text-align: right;
  }
  
  .low-stock {
    color: #F56C81;
    font-weight: bold;
  }
}
</style> 